"""
MKT Original Commentary — Ephesians chapters 5–6
Run: python3 scripts/zc-original-ephesians-5-6.py

Key decisions:
- 5:2 osmē euōdias: LXX sacrificial terminus technicus; same phrase in Phil 4:18 and 2 Cor 2:15
- 5:14 baptismal hymn fragment: analeptic imperative structure; Isa 60:1 LXX closest verbal parallel
- 5:18 plērousthe en pneumati: passive imperative; en instrumental not locative
- 5:21 hypotassomenoi allēlois: mutual submission as the governing principle before household code
- 5:32 to mysterion touto mega estin: demonstrative pronoun refers to Gen 2:24 citation, not to marriage as institution
- 6:12 pros tas archas, exousias: same terms as 1:21 and 3:10; cosmic powers now identified as opponents
- 6:17 machairan tou pneumatos, ho estin rhēma theou: appositive identifies sword = rhēma (specific spoken word), not logos
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

EPHESIANS = {
  "5": {
    "1": '<p><strong>ginesthe oun mimētai tou theou</strong> — <em>mimētai</em> (imitators): the noun appears in Paul also at 1 Cor 4:16; 11:1; Phil 3:17 and 1 Thess 1:6; 2:14. The command to imitate God is unusual — Greek philosophical tradition could speak of assimilation to God (<em>homoiōsis theō</em>, Plato, Theaetetus 176b) but typically as an intellectual-mystical ascent; Paul grounds it in the concrete historical act of Christ\'s love (v2) and in the relational identity of "beloved children" (<em>tekna agapēta</em>). The <em>oun</em> (therefore) links the exhortation to the preceding forgiveness command (4:32) through the logic: as God forgave you in Christ, become imitators of God.</p>',
    "2": '<p><strong>osmē euōdias</strong> — "fragrant aroma" (literally: smell of good aroma): the LXX technical term for the pleasing-aroma of burnt offerings (<em>reah nichoach</em> in MT), used throughout Leviticus (1:9, 13, 17; 2:2, 9, 12; 3:5, etc.) for the acceptable sacrifice. Paul uses the same phrase for the Philippians\' gift (Phil 4:18) and for the believer\'s witness (2 Cor 2:15, <em>osmē</em>). The application of the sacrificial terminus technicus to Christ\'s self-giving places the cross as the definitive sacrifice that all prior offerings anticipated.</p><p><strong>prosphoran kai thysian</strong> — "offering and sacrifice": <em>prosphora</em> is the broader term for any offering brought to God; <em>thysia</em> specifically the sacrifice/slaughtered victim. The pairing covers the entire sacrificial repertoire; Ps 40:6 LXX uses both (<em>thysian kai prosophoron ouk ēthelēsas</em>) in the context of the obedient servant whose body-offering supersedes the animal system.</p>',
    "3": '<p><strong>porneia kai pasa akatharsia ē pleonexia</strong> — "sexual immorality and every impurity or covetousness": the triad will recur in v5 where <em>pleonexia</em> (covetousness) is identified as <em>eidōlolatria</em> (idolatry). The equation of covetousness with idolatry (also Col 3:5) follows the logic that the covetous person worships created goods rather than the Creator. <em>Mēde onomazesthō en hymin</em> — "let it not even be named among you": the prohibition goes beyond non-practice to non-speech — the very naming of these things is inappropriate for the holy community, echoing Levitical purity concerns about the contaminating effect of even associating with the impure.</p>',
    "4": '<p><strong>aischrotēs kai mōrologia ē eutrapelia</strong> — "obscenity, foolish talk, or crude joking": <em>eutrapelia</em> (wit, clever talking, jesting) was a positive virtue in Aristotle\'s ethics (NE 1127b-1128a: the well-bred person who seasons social conversation with apt humor). Paul uses it negatively — not wit per se but the specifically sexual or degrading wit that the context implies. The shift from action to speech (after the action-prohibitions of v3) indicates that the moral formation Paul describes extends from deed to language.</p><p><strong>alla mallon eucharistia</strong> — "but instead thanksgiving" (<em>eucharistia</em>): the antidote to corrupt speech is not merely silence but grateful speech directed toward God. Thanksgiving (<em>eucharistia</em>) reframes the use of language: instead of speech that degrades, speech that glorifies.</p>',
    "5": '<p><strong>pornos ē akathartos ē pleonektēs, ho estin eidōlolatrēs</strong> — the appositive "who is an idolater" (<em>ho estin eidōlolatrēs</em>) is grammatically singular but applies to all three types. The identification of the covetous person specifically as the idolater (not the sexually immoral or the impure) follows because <em>pleonexia</em> is desire for more — an idolatrous relationship to possessions that replaces God with goods. <em>Ouk echei klēronomian en tē basileia tou Christou kai theou</em> — "has no inheritance in the kingdom of Christ and of God": the single governing noun phrase with a single article suggests "the kingdom of Christ-and-God" — a high Christological formulation linking Christ and God as co-rulers of the one kingdom.</p>',
    "6": '<p><strong>mē tis humas apatātō kenois logois</strong> — "let no one deceive you with empty words" (<em>kenois logois</em>: hollow, without content — <em>kenos</em> contrasts with the fullness language throughout Ephesians): the deception consists in rationalizing the sins of vv3-5 as inconsequential. <strong>huioi tēs apeithias</strong> (sons of disobedience) — the identical phrase as 2:2, recalling the pre-conversion existence of all believers under the power of disobedience; the reminder is that these behaviors are not a neutral lifestyle but the defining characteristic of the unregenerate humanity. <strong>erchetai hē orgē tou theou</strong> — the present-tense <em>erchetai</em> (comes, is coming) treats the wrath of God as already operative in the present age, not merely a future eschatological threat; the wrath falls <em>epi</em> (upon/on account of) these very things.</p>',
    "7": '<p><strong>mē oun ginesthe synkoinōnoi autōn</strong> — "do not therefore become co-participants with them" (<em>synkoinōnoi</em>: fellow-partakers; the <em>syn</em>-compound makes the complicity explicit — to be a fellow-participant is to share in the act and its consequences): the <em>oun</em> draws the practical consequence from v6. The warning is not merely against practice but against fellowship-in-the-acts: partial involvement, social tolerance of the deeds, looking on without protest. The verse closes the warning section (vv3-7) before the light-identity section opens (v8).</p>',
    "8": '<p><strong>ēte gar pote skotos, nyn de phōs en kyriō</strong> — "for you were once darkness, now you are light in the Lord": the radical ontological formulation — not "you were in darkness" but "you were darkness"; not "you are in light" but "you are light." The participatory-ontological language (<em>en kyriō</em>, in the Lord) grounds the identity transformation: the new identity is not achieved but received through union with the one who is light (cf. John 8:12). The past-tense <em>ēte</em> (were) and present-tense <em>este</em> (implied: are) mark the temporal boundary of conversion.</p>',
    "9": '<p><strong>ho gar karpos tou phōtos</strong> — "for the fruit of the light": some manuscripts read <em>karpos tou pneumatos</em> (fruit of the Spirit, as in Gal 5:22) — a scribal harmonization; the best textual tradition reads <em>phōtos</em> (light). The organic metaphor of fruit distinguishes Spirit/light-produced morality from law-compelled behavior: fruit grows from the life of the tree, not from external constraint. The triad <em>agathōsynē kai dikaiosynē kai alētheia</em> (goodness, righteousness, truth) are the characteristic qualities of the light-community.</p>',
    "10": '<p><strong>dokimazein ti estin euareston tō kyriō</strong> — "discerning what is pleasing to the Lord" (<em>dokimazein</em>): the testing-and-approving verb that Paul uses for moral discernment throughout (Rom 12:2; Phil 1:10; 1 Thess 5:21). The capacity for moral discernment is the practical outworking of the light-identity: those who are light discern what pleases the Lord through attentive, Spirit-formed judgment rather than rule-application.</p>',
    "11": '<p><strong>ta erga ta akarpa tou skotous</strong> — "the fruitless works of darkness" (<em>akarpa</em>, without fruit, barren): the opposite of the fruit of light (v9). Darkness produces <em>erga</em> (works, deeds) that are by nature <em>akarpa</em> — they generate nothing lasting, no genuine good. <em>Mē synkoinōneite</em> — "do not participate with" (<em>synkoinōneō</em> = to share together in): the <em>syn</em>-compound emphasizes complicity; the command is to have no joint participation in the darkness-deeds, while <em>elengnete de mallon</em> (but rather expose them) requires active counter-action.</p>',
    "12": '<p><strong>ta gar kryptē ginomena hyp\' autōn aischron estin kai legein</strong> — "for the things done by them in secret it is shameful even to speak of" (<em>kryptē</em>: in hiddenness, in secret; <em>aischron</em>: shameful, dishonorable — the word of social disgrace in the honor-shame register): their deeds require concealment precisely because they cannot bear public scrutiny; this is the negative ground for the exposure command (v11). The verse does not name the specific deeds but gestures toward them — the shame is compounded by description, so the text maintains decorum by refusing to specify. The <em>estin kai legein</em> (it is [shameful] even to speak of) intensifies: not merely doing them but naming them participates in the dishonor.</p>',
    "13": '<p><strong>ta de panta elegchomena hypo tou phōtos phaneroutai</strong> — "but everything exposed by the light is made visible" (<em>elegchō</em>: to reprove, expose, convict — the word used for the Spirit\'s convicting work in John 16:8; <em>phaneroo</em>: to make manifest, render visible): the logic: what is reproved by the light does not simply get condemned — it gets made manifest, drawn into visibility. <strong>pan gar to phaneromenon phōs estin</strong> — "for everything that is made manifest is light" — the most striking claim: exposure by the light is not merely revelation of darkness but transformation into light. The verse grounds the imperative to expose (v11) in this ontological logic: the act of exposure-by-light is itself the act of light-transformation, not merely condemnation.</p>',
    "14": '<p><strong>Dio legei, Egeire, ho katheudōn, kai anasta ek tōn nekrōn, kai epiphausei soi ho Christos</strong> — "Therefore it says: Awake, O sleeper, and arise from the dead, and Christ will shine on you": the source formula <em>dio legei</em> (therefore it says) elsewhere introduces Scripture (4:8; 5:14 is the only NT use without clear scriptural antecedent). The fragment is most likely a baptismal hymn that Paul cites as authoritative — the closest verbal parallel is Isa 60:1 LXX (<em>phōtizou phōtizou Ierousalēm hēkei gar sou to phōs kai hē doxa kyriou epi se anatelalen</em> = arise, shine, for your light has come). The three imperatives (wake, arise, Christ-will-shine) follow the analeptic pattern of baptismal awakening — the conversion-to-light experience rendered in poetic form.</p>',
    "15": '<p><strong>blepete oun akribōs pōs peripateite</strong> — "pay careful attention then to how you walk" (<em>akribōs</em>: precisely, exactly, carefully — the same word for the Magi\'s careful inquiry about the star in Matt 2:7): the <em>peripateo</em> (walk) metaphor, used throughout Ephesians for the pattern of life (2:2, 10; 4:1, 17; 5:2, 8, 15), is here governed by <em>akribōs</em> — deliberate, watchful attention to the direction of one\'s life. <em>Mē hōs asophoi all\' hōs sophoi</em> — "not as unwise but as wise": the wisdom frame recasts the moral life as a matter of perception and judgment (<em>sophia</em>) rather than rule-compliance.</p>',
    "16": '<p><strong>exagorazomenoi ton kairon</strong> — "buying back the time, making the most of the opportunity" (<em>exagorazō</em>: to buy out of the marketplace, redeem by paying the price): the commercial metaphor implies seizing the available opportunity before it closes — the <em>kairos</em> (opportune time, moment) is not <em>chronos</em> (measured clock-time) but the specific moment with its unique potential. Col 4:5 uses the identical phrase in the context of behavior toward outsiders. <em>Hoti hai hēmerai ponērai eisin</em> — "because the days are evil": the eschatological pressure grounds the urgency; the present age is evil but time-limited, making every available moment for redemptive action urgent.</p>',
    "17": '<p><strong>mē ginesthe aphrōnes, alla syniete ti to thelēma tou kyriou</strong> — "do not be foolish, but understand what the will of the Lord is" (<em>syniete</em>: second-person plural imperative of <em>syniēmi</em>, to comprehend through assembly of parts): the wisdom-foolishness polarity (cf. Prov 8-9) governs understanding the divine will. The will of the Lord is not a specific list of behaviors but a pattern of reality to be understood (<em>syniete</em>) through wisdom-formation — the Spirit-filled community discerns it in worship and community life (vv18-21).</p>',
    "18": '<p><strong>mē methyskaesthe oinō, en hō estin asōtia, alla plērousthe en pneumati</strong> — "do not get drunk with wine — in which is debauchery — but be filled with the Spirit" (<em>asōtia</em>: prodigal, reckless living; same word for the prodigal son\'s lifestyle in Luke 15:13): the contrast is not between alcohol and abstinence but between two kinds of altered state and two kinds of communal expression — wine-filling produces pagan revelry; Spirit-filling produces the worship described in vv19-21. <em>Plērousthe</em> is a present passive imperative: keep being filled, continuously receive the filling — the ongoing work of the Spirit in the community. <em>En pneumati</em> — "in the Spirit" (instrumental or sphere): the Spirit is both the means and the environment of the filling.</p>',
    "19": '<p><strong>psalmois kai hymnois kai ōdais pneumatikais</strong> — "in psalms and hymns and spiritual songs" (<em>Col 3:16 uses an identical phrase</em>): the three terms may represent (a) three distinct genres (Psalter/OT psalms, composed Christian hymns, Spirit-improvised songs); or (b) overlapping categories for the full range of community song. <em>Pneumatikais</em> (spiritual) may modify all three nouns (psalms, hymns, songs that are all Spirit-given) rather than only the third. <em>Adōntes kai psallontes tē kardia hymōn tō kyriō</em> — "singing and making melody with your heart to the Lord": <em>psallō</em> originally meant to pluck a string instrument but by the NT period generally meant to sing praise. "With your heart" (<em>tē kardia</em>) — inner participation not only outer performance.</p>',
    "20": '<p><strong>eucharistountes pantote hyper pantōn en onomati tou kyriou hēmōn Iēsou Christou tō theō kai patri</strong> — "always giving thanks to God the Father for all things in the name of our Lord Jesus Christ": <em>eucharistountes</em> is the fourth present participle in the Spirit-filling sequence of vv18-21 (alongside speaking, singing, making melody, and submitting — v21), not a separate command but a continuous fruit of Spirit-filling. <em>Pantote... hyper pantōn</em> — "always... for all things": the double universality (all times, all circumstances) is the theologically demanding feature; the thanksgiving encompasses what cannot be received as good on its own terms, grounded in the mediation of Christ\'s name. <em>En onomati tou kyriou hēmōn</em> (in the name of our Lord) — thanksgiving is directed to the Father <em>through</em> the Christ-name, the same mediated access described in 2:18 (<em>di\' autou tēn prosagōgēn</em>).</p>',
    "21": '<p><strong>hypotassomenoi allēlois en phobō Christou</strong> — "submitting to one another in the fear of Christ": the present middle/passive participle <em>hypotassomenoi</em> (submitting, being subject) is syntactically dependent on <em>plērousthe</em> (v18), making mutual submission the fifth result of Spirit-filling (alongside speaking, singing, giving thanks). The <em>allēlois</em> (one another, mutually) is the governing principle: the submission is reciprocal before it is hierarchical. The household code that follows (5:22-6:9) elaborates specific relational dynamics within this mutuality, not as an exception to it but as its concrete application in asymmetric relationships.</p>',
    "22": '<p><strong>hai gynaikes tois idiois andrasin hōs tō kyriō</strong> — "wives to their own husbands as to the Lord": the verb is absent in the best manuscripts (supplied from v21\'s <em>hypotassomenoi</em>): "wives [submitting] to your own husbands." The <em>idiois</em> (own) specifies the husband in the particular marriage relationship — not a general female subordination to males but the specific marital relationship. <em>Hōs tō kyriō</em> (as to the Lord): the submission\'s quality and motive are shaped by the Christ-relationship; the husband functions as a representational analogy of the Lord, not as a substitute lord.</p>',
    "23": '<p><strong>hoti anēr estin kephalē tēs gynaikos hōs kai ho Christos kephalē tēs ekklēsias, autos sōtēr tou sōmatos</strong> — "because the husband is the head of the wife as also Christ is the head of the church, he himself being the savior of the body": <em>kephalē</em> (head) is debated: (a) source/origin (as in 4:15-16 where the head is the source from which the body grows); (b) authority-over (as in the common OT/Greek usage for rulers). The Christ-analogy determines what headship means: Christ\'s headship is exercised as savior of the body — a life-giving, self-sacrificial role. <em>Autos sōtēr tou sōmatos</em> (he himself the savior of the body) is the defining qualification: headship in this context is characterized by saving rather than dominating.</p>',
    "24": '<p><strong>alla hōs hē ekklēsia hypotassetai tō Christō, houtōs kai hai gynaikes tois andrasin en panti</strong> — "but as the church submits to Christ, so also wives to husbands in everything": <em>hypotassetai</em> (is subject, submits) — present tense, indicating the ongoing reality of the church\'s submission as the paradigm: not an occasional act but a continuous posture. The <em>alla</em> (but) marks the concessive move: after v23\'s christological grounding of headship, this verse draws the analogical application. The church\'s submission is not merely an illustration but the formative model — the wife\'s submission is characterized by the quality and grounding of the church\'s submission to Christ. <em>En panti</em> (in everything) — the scope parallels the total self-sacrifice demanded of husbands in v25; the asymmetry is in role, not in totality.</p>',
    "25": '<p><strong>hoi andres, agapate tas gynaikas, kathōs kai ho Christos ēgapēsen tēn ekklēsian kai heauton paredōken hyper autēs</strong> — "husbands, love your wives as also Christ loved the church and gave himself up for her" (<em>paredōken</em>: aorist active of <em>paradidōmi</em>, delivered over, handed over — the same verb used for Judas\'s betrayal-handover and for God\'s delivering Jesus to death in Rom 4:25; 8:32): the measure of husband-love is the cross. The self-handover language places the husband\'s love explicitly in the economy of Christ\'s atoning self-giving — not a softer version but the full measure.</p>',
    "26": '<p><strong>hagiasē autēn katharisas tō loutrō tou hydatos en rhēmati</strong> — "having cleansed her by the washing of water with the word/in word" (<em>tō loutrō tou hydatos</em> = the bath/washing of water): <em>loutron</em> (washing, bath) refers to baptism in Titus 3:5; here the washing of water is the instrument of the church\'s purification. <em>En rhēmati</em> (in/with word) — the accompanying word: either (a) the baptismal confession or formula spoken at baptism; (b) the gospel-word that accompanied the baptismal event; or (c) the word of Scripture. The purpose clause <em>hina autēn hagiasē</em> (that he might sanctify her) identifies the washing as the instrument of sanctification — the eschatological purity of the church is already enacted in the community\'s baptism.</p>',
    "27": '<p><strong>hina parastēsē autos heautō endoxon tēn ekklēsian mē echousan spillon ē rhytida ē ti tōn toioutōn all\' hina ē hagia kai amōmos</strong> — "that he might present the church to himself in splendor, without spot or wrinkle or any such thing, but so that she might be holy and without blemish": <em>parastēsē</em> (present, place alongside) is the presenting of a bride at the wedding or of a sacrifice at the altar. <em>Endoxon</em> (in glory/splendor) — the eschatological presentation has a radiant quality. The bridal purity vocabulary (<em>spillon</em> = spot/stain; <em>rhytida</em> = wrinkle — NT hapax legomena) describes unblemished beauty. <em>Hagia kai amōmos</em> (holy and without blemish) is the Levitical standard for sacrificial animals applied to the church-as-bride.</p>',
    "28": '<p><strong>houtōs opheilousin kai hoi andres agapan tas heautōn gynaikas hōs ta heautōn sōmata</strong> — "in this same way, husbands ought to love their own wives as their own bodies" (<em>opheilousin</em>: ought, are obligated — debt-language; the husband\'s love is not optional sentiment but moral necessity): the <em>houtōs</em> (in this same way) applies the Christ-church pattern of vv25-27 to the self-care argument: as Christ nourishes the church which is his body, so the husband who loves his wife loves his own body-in-her (since they are one flesh, v31). <em>Ho agapōn tēn heautou gynaika heauton agapā</em> — "he who loves his own wife loves himself": the self-love argument does not sanction selfishness but subverts it — the husband cannot treat his wife as other because she is, in the one-flesh union, himself.</p>',
    "29": '<p><strong>oudeis gar pote tēn heautou sarka emisēsen, alla ektrephei kai thalpei autēn</strong> — "for no one ever hated his own flesh, but nourishes and cherishes it" (<em>ektrephō</em>: to nourish, bring to maturity — used in 6:4 for raising children; <em>thalpō</em>: to warm, cherish, tend with protective care — Paul uses it in 1 Thess 2:7 for his own maternal nursing of the community): the two verbs together describe attentive bodily care — feeding and warming. <em>Kathōs kai ho Christos tēn ekklēsian</em> — the self-care analogy points beyond itself to Christ\'s care of the church as the governing instance; the husband\'s care of his wife is measured by and participates in Christ\'s care of the body. What Christ does for the church — nourish and cherish — is the template for husband-love, not merely an analogy.</p>',
    "30": '<p><strong>hoti mele esmen tou sōmatos autou</strong> — "because we are members of his body": the <em>hoti</em> (because) provides the ground for v29\'s claim that Christ nourishes and cherishes the church — he does so because it is his body, of which believers are members. <em>Mele</em> (members, limbs) — the body-membership language is the foundation for the husband-love argument: as the husband\'s care for his wife follows from their one-flesh union, Christ\'s care for the church follows from the believers\' incorporation into his body. Some manuscripts add <em>ek tēs sarkos autou kai ek tōn osteōn autou</em> (from his flesh and from his bones), echoing Adam\'s cry over Eve in Gen 2:23 — if original, it deepens the Adam-Christ/Eve-church typology that the citation of Gen 2:24 (v31) makes explicit.</p>',
    "31": '<p><strong>anti toutou kataleipsei anthrōpos ton patera kai tēn mētera kai proskollēthēsetai pros tēn gynaika autou, kai esontai hoi dyo eis sarka mian</strong> — Paul cites Gen 2:24 LXX (with minor variations): <em>anti toutou</em> (therefore/for this reason) begins the citation. The <em>proskollāō</em> (cleave to, be glued/joined to) emphasizes the permanence of the bond. <em>Eis sarka mian</em> (into one flesh) is the ontological union of marriage that Paul will interpret as the mysterion in v32.</p>',
    "32": '<p><strong>to mysterion touto mega estin; egō de legō eis Christon kai eis tēn ekklēsian</strong> — "this mystery is great; I am speaking with reference to Christ and the church": the demonstrative <em>touto</em> refers back to the Gen 2:24 citation — the mystery is in the ancient text, not simply in the institution of marriage. Paul\'s interpretive move (<em>egō de legō</em>: I am saying, for my part) applies the one-flesh text to the Christ-church union: the "great mystery" is the deep meaning hidden in the creation ordinance, now disclosed in the gospel. This is the typological hermeneutic at work: the human marriage pattern in creation always already pointed toward its antitype in the covenant union of Christ and the church.</p>',
    "33": '<p><strong>plēn kai hymeis hoi kath\' hena, hekastos tēn heautou gynaika houtōs agapatō hōs heauton, hē de gynē hina phobētai ton andra</strong> — "nevertheless, each one of you is to love his wife as himself, and the wife is to fear/respect her husband" (<em>phobētai</em>: the verb of reverence/fear, the same as <em>phobō Christou</em> in v21): <em>plēn</em> (nevertheless, however) transitions from the theological mysterion to the practical summary. The husband\'s love-obligation and the wife\'s respect-obligation are the two asymmetric requirements that flow from the Christ-church analogy. <em>Phobos</em> here is reverential respect, not terror — the same quality that characterizes the community\'s relation to Christ (v21).</p>'
  },
  "6": {
    "1": '<p><strong>ta tekna, hypakouete tois goneusin hymōn en kyriō, touto gar estin dikaion</strong> — "children, obey your parents in the Lord, for this is right" (<em>hypakouō</em>: to obey, listen under, respond to as an authority — from <em>hypo</em> + <em>akouō</em>): the address to children directly (<em>ta tekna</em>) assumes their presence in the assembled community where the letter is read — they are full members of the household of God who can receive instruction. <em>En kyriō</em> (in the Lord): the Lord-reference qualifies the obedience (ultimate allegiance belongs to the Lord, not parents absolutely) and motivates it (obedience to parents is a practice of the Lord-shaped life). <em>Touto gar estin dikaion</em> (for this is right, just) — the appeal to natural-order rightness supplements the appeal to Torah.</p>',
    "2": '<p><strong>tima ton patera sou kai tēn mētera</strong> — Paul cites Exod 20:12 (Deut 5:16) with the qualifying phrase <em>hētis estin entolē prōtē en epangeliai</em> (which is the first commandment with a promise): <em>prōtē en epangeliai</em> — "first in/with promise." This is a notable rabbinic-style classification: Paul identifies the fifth commandment as uniquely carrying an attached promise, distinguishing it within the Decalogue. The Decalogue\'s first four commandments concern God directly; the fifth begins the human-relations series and carries the specific land-promise that Paul applies eschatologically.</p>',
    "3": '<p><strong>hina eu soi genētai kai esē makrochronios epi tēs gēs</strong> — "that it may go well with you and that you may live long in the land": Paul reproduces the Deuteronomy version of the promise (<em>hina eu soi genētai kai makrochronios esē epi tēs gēs agathēs</em>: Deut 5:16 LXX). The land-promise (<em>epi tēs gēs</em>, upon the earth/land) is neither spiritualized away nor confined to Israel\'s territory — the <em>gē</em> (earth/land) functions eschatologically as the renewed creation that the meek will inherit (Matt 5:5; cf. Ps 37:11). The promise grounds the command in covenantal consequence: honoring parents is embedded in a world that rewards covenant faithfulness.</p>',
    "4": '<p><strong>hoi pateres, mē parorgizete ta tekna hymōn</strong> — "fathers, do not provoke your children to anger" (<em>parorgizō</em>: to irritate thoroughly, provoke to wrath — the <em>para</em> intensifies the <em>orgizō</em>): Col 3:21 uses the synonym <em>erethizō</em> (to irritate, stir up). The address to fathers specifically (not "parents" — <em>pateres</em>, masculine) targets the paterfamilias, the Roman family head who held legal authority (<em>patria potestas</em>) over children and whose harshness was the primary threat to children\'s formation. <em>Alla ektrephete auta en paideia kai nouthesia kyriou</em> — "but bring them up in the discipline and instruction of the Lord" (<em>ektrephō</em>: to nourish, bring up; <em>paideia</em>: formation, training, discipline; <em>nouthesia</em>: admonition, instruction-by-words).</p>',
    "5": '<p><strong>hoi douloi, hypakouete tois kata sarka kyriois meta phobou kai tromou en haplotēti tēs kardias hymōn hōs tō Christō</strong> — "slaves, obey your earthly masters with fear and trembling, with a sincere heart, as to Christ" (<em>kata sarka kyriois</em>: fleshly masters, masters according to the flesh — the qualifier marks the relativity of the human lordship by distinguishing it from the kyrios-relationship to Christ): <em>meta phobou kai tromou</em> (with fear and trembling) is Paul\'s idiom for the serious attentiveness owed in a relationship of great consequence (cf. 1 Cor 2:3; 2 Cor 7:15; Phil 2:12). <em>En haplotēti tēs kardias</em> (with singleness/sincerity of heart) — undivided inner orientation, contrasted with eye-service.</p>',
    "6": '<p><strong>mē kat\' ophthalmodoulian hōs anthrōpareskoi alla hōs douloi Christou poiountes to thelēma tou theou ek psychēs</strong> — "not with eye-service as people-pleasers, but as slaves of Christ doing the will of God from the soul" (<em>ophthalmodouleia</em>: eye-slavery, service performed only when watched — NT hapax, also Col 3:22; likely Paul\'s coinage): <em>anthrōpareskoi</em> (people-pleasers): another rare compound; the opposite of the single-minded God-pleasing that Paul commends. <em>Hōs douloi Christou</em> (as slaves of Christ): the deeper identity relativizes the human slavery — every believer-slave is already a slave of Christ, which reframes all human service as ultimately directed toward Christ.</p>',
    "7": '<p><strong>met\' eunoias douleuontes hōs tō kyriō kai ouk anthrōpois</strong> — "serving with good will as to the Lord and not to people" (<em>eunoias</em>: benevolence, good will — the generous inner disposition that makes service genuinely willing rather than grudging): the phrase completes and reinforces v6\'s reframing: service oriented to the Lord is characterized by <em>eunoias</em>, not by the calculated performance of the people-pleaser. The repetition of <em>hōs tō kyriō kai ouk anthrōpois</em> (as to the Lord and not to people) in successive verses is emphatic — the principle requires double declaration to be internalized.</p>',
    "8": '<p><strong>eidotes hoti hekastos ean ti agathon poiēsē, touto komietai para kyriou, eite doulos eite eleutheros</strong> — "knowing that each one, if he does anything good, will receive this back from the Lord, whether slave or free" (<em>eidotes</em>: knowing — participial grounding; behavioral transformation flows from knowledge of eschatological reality): <em>komizō</em> (to receive, carry away) has a commercial register suggesting receiving what is due — the eschatological recompense is cast as a settled accounting. <em>Eite doulos eite eleutheros</em> (whether slave or free) — the social leveling is the most radical implication of the Christ-slavery framework: the Lord\'s assessment operates independently of the earthly status distinction, registering every good act regardless of whether the actor has social standing. This is the ground on which the slave\'s faithful service has eternal weight equal to the free person\'s.</p>',
    "9": '<p><strong>kai hoi kyrioi, ta auta poieite pros autous, aniēntes tēn apeilēn</strong> — "and masters, do the same to them, giving up the threat" (<em>aniēntes</em>: releasing, letting go of — from <em>aniēmi</em>, to let go, release; same word used for releasing prisoners): the command to "do the same things" (<em>ta auta poieite</em>) toward slaves creates a reciprocity that the standard household code tradition did not: masters are to apply the same sincere-hearted service-orientation toward their slaves that they require of their slaves. <em>Eidotes hoti kai autōn kai hymōn ho kyrios estin en ouranois kai prosōpolēmpsia ouk estin par\' autō</em> — the theological grounding: both slave and master have the same Lord in heaven, and this Lord shows no partiality (<em>prosōpolēmpsia</em> = face-receiving, partiality).</p>',
    "10": '<p><strong>tou loipou, endynamousthe en kyriō kai en tō kratei tēs ischyos autou</strong> — "finally, be strengthened in the Lord and in the strength of his might" (<em>endynamousthe</em>: present passive imperative — keep being empowered, continue receiving strength): <em>en kyriō</em> (in the Lord) is again the sphere of divine strengthening. <em>Kratei tēs ischyos</em> (strength of his might): <em>kratos</em> (power, dominion) and <em>ischys</em> (strength, force) — the same doublet as 1:19 where God\'s power toward believers is described as <em>to hyperballon megethos tēs dynameōs... kata tēn energeian tou kratous tēs ischyos autou</em>. The armor section elaborates what this empowered-in-the-Lord state looks like concretely.</p>',
    "11": '<p><strong>endysasthe tēn panoplian tou theou</strong> — "put on the full armor of God" (<em>panoplia</em>: the complete armor set of a heavy infantryman, covering all parts of the body — from <em>pan</em> + <em>hopla</em>): the term <em>panoplia</em> is rare and specifically military; Isa 59:17 LXX uses <em>panoplia</em> for the divine warrior\'s complete equipment. The genitive <em>tou theou</em> (of God) is both possessive (God\'s own armor) and source (armor that God provides): believers are equipped with the divine warrior\'s own equipment. <em>Pros to dynasthai hymas stēnai pros tas methodias tou diabolou</em> — "so that you may be able to stand against the schemes of the devil" (<em>methodias</em>: scheming, craftiness, strategic deception — used in 4:14 for human deception).</p>',
    "12": '<p><strong>hoti ouk estin hēmin hē palē pros haima kai sarka alla pros tas archas, pros tas exousias, pros tous kosmokratoras tou skotous toutou, pros ta pneumatika tēs ponērias en tois epouraniois</strong> — "for our struggle is not against flesh and blood but against the rulers, against the authorities, against the cosmic powers of this present darkness, against the spiritual forces of evil in the heavenly places" (<em>palē</em>: wrestling, grappling combat — the word for the ancient wrestling match): the four-term list of cosmic powers (<em>archai, exousiai, kosmokratores, pneumatika tēs ponērias</em>) recapitulates the powers language of 1:21 and 3:10, now identified as the adversaries in the spiritual battle. <em>Kosmokratoras tou skotous toutou</em> (world-rulers of this darkness) — a rare compound; the cosmological dualism identifies a present-age power structure under the authority of darkness. <em>En tois epouraniois</em> (in the heavenly places) — the same sphere where Christ is exalted (1:20) and where the church is seated (2:6): the heavenly conflict is already partly decided by Christ\'s exaltation.</p>',
    "13": '<p><strong>dia touto analabete tēn panoplian tou theou</strong> — "therefore take up the full armor of God" (<em>analabete</em>: aorist active imperative — a decisive act of reception): the <em>dia touto</em> (therefore, because of this) grounds the imperative in the nature of the opponents named in v12: because the adversaries are cosmic powers, not human antagonists, only God\'s own armor suffices. <strong>hina dynēthēte antistēnai en tē hēmera tē ponēra</strong> — "that you may be able to withstand in the evil day" (<em>antistēnai</em>: to stand against, resist — aorist active infinitive): <em>hē hēmera hē ponēra</em> (the evil day) may refer to (a) the final eschatological crisis; (b) any acute day of spiritual testing; both senses are supported by the letter\'s already-and-not-yet eschatology. <strong>hapanta katergazamenoi stēnai</strong> — "having done/worked through everything, to stand firm": <em>katergazomai</em> (to accomplish through sustained effort, work to completion) followed by <em>stēnai</em> — the full armor enables both active engagement with the enemy and the final firm stance after the engagement.</p>',
    "14": '<p><strong>stēte oun perizōsamenoi tēn osphyn hymōn en alētheia kai endysamenoi ton thōraka tēs dikaiosynēs</strong> — "stand therefore, having fastened the belt of truth around your waist and having put on the breastplate of righteousness" (<em>perizōsamenoi</em>: perfect middle participle of <em>perizōnnymi</em>, to gird around): the belt/girdle of truth secures the other armor pieces (the <em>zōnē</em> held the sword and kept the breastplate in place). <em>En alētheia</em> (in truth): the prepared, secured stance of truthfulness that supports all other spiritual equipment. <em>Thōraka tēs dikaiosynēs</em> — "breastplate of righteousness": either (a) the imputed righteousness of Christ (the forensic gift that protects against condemnation); or (b) the practiced righteousness of upright life (the ethical armor); both senses likely operative, as Isa 59:17\'s divine warrior wears the righteousness that he both embodies and executes.</p>',
    "15": '<p><strong>kai hypodēsamenoi tous podas en hetoimasia tou euangeliou tēs eirēnēs</strong> — "and having strapped on your feet the readiness of the gospel of peace" (<em>hypodēsamenoi</em>: having bound underneath, sandaled — the military sandal was the caliga, the hobnailed boot of the Roman legionary): <em>hetoimasia</em> (readiness, preparation, firm foundation) — the feet of the gospel-bearer are readied, stabilized by the message they carry. The gospel of peace is both the message proclaimed and the stabilizing force underfoot: the one who carries the peace-message stands firm because peace grounds them. Isa 52:7\'s feet of the good-news-bearer are the direct OT background.</p>',
    "16": '<p><strong>en pasin analabontes ton thyreon tēs pisteōs</strong> — "in all [circumstances], having taken up the shield of faith" (<em>thyreon</em>: the large door-shaped rectangular shield of the Roman legionary, as opposed to the <em>aspis</em>, the smaller round shield): the <em>thyreon</em> was approximately 4 feet tall and 2.5 feet wide, designed to cover the whole body and to interlock with adjacent soldiers\' shields in the <em>testudo</em> formation — a communal as well as individual defense. <em>En hō dynēsesthe panta ta belē tou ponērou ta pepyrōmena sbesai</em> — "with which you will be able to extinguish all the flaming arrows of the evil one" (<em>pepyrōmena</em>: having been set on fire — incendiary projectiles used in ancient siege warfare).</p>',
    "17": '<p><strong>kai tēn perikephalaian tou sōtēriou dexasthe kai tēn machairan tou pneumatos, ho estin rhēma theou</strong> — "and receive the helmet of salvation and the sword of the Spirit, which is the word of God": <em>dexasthe</em> (receive, take) — the middle aorist imperative suggests an act of reception rather than self-equipping: the helmet is given, received. <em>Perikephalaia tou sōtēriou</em> (helmet of salvation): Isa 59:17 LXX reads <em>perikephalaian sōtēriou</em> — Paul uses the identical phrase with the article. <em>Machairan tou pneumatos</em> — "sword of the Spirit" (<em>machaira</em>: the short sword used in close combat, not the <em>rhomphaia</em> = long sword): <em>ho estin rhēma theou</em> — the appositive identifies the sword: <em>rhēma</em> (specific spoken word, utterance) rather than <em>logos</em> (the broader word/reason/message). The Spirit\'s sword is the specific, situationally appropriate divine word spoken in the moment.</p>',
    "18": '<p><strong>dia pasēs proseuchēs kai deēseōs proseuchomenoi en panti kairō en pneumati</strong> — "praying at all times in the Spirit with every prayer and petition" (<em>proseuchē</em>: prayer generally; <em>deēsis</em>: specific supplication or petition for a need — the pairing covers both general communion and specific intercession): <em>en panti kairō</em> (at every opportune moment, at all times) — the kairological time of prayer: every occasion is an occasion for prayer. <em>En pneumati</em> (in the Spirit): the Spirit is the element and power in which prayer occurs; cf. Rom 8:26-27 where the Spirit intercedes within the believer\'s prayer. <em>Eis auto agrypnountes en pasē proskarterēsei kai deēsei peri pantōn tōn hagiōn</em> — "keeping alert with all perseverance, making supplication for all the saints": <em>agrypneō</em> (to be sleepless, stay awake, keep watch) — the prayer-watch language.</p>',
    "19": '<p><strong>kai hyper emou, hina moi dothē logos en anoixei tou stomatos mou, en parrēsia gnōrisai to mystērion tou euangeliou</strong> — "and for me, that words may be given to me in opening my mouth boldly to make known the mystery of the gospel" (<em>anoixei tou stomatos mou</em>: in opening of my mouth — the idiom for beginning to speak publicly, Ezek 3:27; 33:22; Acts 8:35): <em>en parrēsia</em> (with boldness, with freedom of speech) — the rhetorically confident, frank speech that fear might suppress; the same courage Paul will specify as the means of his ambassadorial task in v20. <em>To mystērion tou euangeliou</em> (the mystery of the gospel): the <em>mysterion</em> that has been the letter\'s major theme (1:9; 3:3-6, 9; 5:32) — the Jew-Gentile unity in Christ now applied to Paul\'s specific vocation to proclaim it.</p>',
    "20": '<p><strong>hyper hou presbeuo en halysei, hina en autō parrēsiasōmai hōs dei me lalēsai</strong> — "for which I am an ambassador in chains, that I may declare it boldly as I ought to speak" (<em>presbeuō</em>: to be an ambassador, represent as an envoy — the official term for diplomatic representation of a superior): Paul uses the same term in 2 Cor 5:20 for the apostolic ambassadorship of reconciliation. The paradox of <em>presbeuō en halysei</em> (ambassador in chains/fetters) is deliberate: the highest diplomatic office combined with the prisoner\'s condition. <em>Hōs dei me lalēsai</em> (as it is necessary for me to speak) — the apostolic compulsion that overrides the circumstances of imprisonment.</p>',
    "21": '<p><strong>Tychikos ho agapētos adelphos kai pistos diakonos en kyriō gnōrisei hymin panta ta kat\' eme</strong> — "Tychicus, the dear brother and faithful servant in the Lord, will make known to you all things about me" (<em>Tychikos</em>: attested in Acts 20:4 as an Asian co-traveler; the letter-carrier in Col 4:7-8, 2 Tim 4:12, Titus 3:12): Tychicus functions as the authorized interpreter of the letter, carrying not just the document but information about Paul\'s situation that the letter itself does not supply. <em>Agapētos adelphos kai pistos diakonos en kyriō</em> (dear brother and faithful servant in the Lord) — the double honorific establishes Tychicus\'s trustworthiness as a tradent; the community can receive his oral report as reliably as the letter. This reliance on a letter-carrier for supplemental information was standard Hellenistic epistolary practice.</p>',
    "22": '<p><strong>hon epempsa pros hymas eis auto touto, hina gnōte ta peri hēmōn kai parakalesē tas kardias hymōn</strong> — "whom I have sent to you for this very purpose, that you may know the things about us and that he may encourage your hearts" (<em>eis auto touto</em>: for this very thing, deliberately and specifically — the commission is purposive): <em>parakalesē tas kardias hymōn</em> (that he may encourage/exhort your hearts) — <em>parakaleō</em> encompasses both comfort and exhortation; <em>kardias</em> (hearts, the center of inner life and decision) is the target of Tychicus\'s ministry. The community\'s hearts may be troubled by Paul\'s imprisonment (3:13 already addressed this: "do not lose heart"); Tychicus\'s visit and report are the pastoral means of stabilizing that inner distress. The sending of a trusted envoy to carry and explain a letter is the normal practice of Pauline mission correspondence.</p>',
    "23": '<p><strong>eirēnē tois adelphois kai agapē meta pisteōs apo theou patros kai kyriou Iēsou Christou</strong> — "peace to the brothers and sisters, and love with faith, from God the Father and the Lord Jesus Christ": the closing blessing mirrors the letter\'s opening (<em>charis hymin kai eirēnē apo theou patros hēmōn kai kyriou Iēsou Christou</em>, 1:2), completing the epistolary frame. <em>Agapē meta pisteōs</em> (love with faith) — an unusual pairing: the two are joined as inseparable; the love that characterizes the community is a love that flows from and is sustained by faith. <em>Apo theou patros kai kyriou Iēsou Christou</em> — the double divine source is the same high Christological formula as 1:2; the letter that began with Christ and God as co-sources of grace and peace closes with them as co-sources of peace and love.</p>',
    "24": '<p><strong>hē charis meta pantōn tōn agapōntōn ton kyrion hēmōn Iēsoum Christon en aphtharsia</strong> — "grace be with all those who love our Lord Jesus Christ in incorruptibility/immortality" (<em>en aphtharsia</em>: in incorruptibility, with unfading love, with imperishability): the closing <em>en aphtharsia</em> is the most unusual element of any Pauline epistolary closing. It modifies either: (a) the <em>agapōntōn</em> (those who love with an undying love); or (b) the grace (that endures imperishably). Either reading places the eschatological dimension of the Christ-love at the forefront of the closing: the love of Christ that the community embodies is of the quality of the imperishable age, not the perishing present age.</p>'
  }
}

def main():
    existing = load_comm('mkt-original', 'ephesians')
    merge_comm(existing, EPHESIANS)
    save_comm('mkt-original', 'ephesians', existing)
    total = sum(len(v) for v in existing.values())
    print(f'Ephesians mkt-original: {len(existing)} chapters, {total} verses written.')

if __name__ == '__main__':
    main()
